function freqColor(pct){
  if(pct>=60) return "var(--bad)";
  if(pct>=30) return "var(--mid)";
  return "var(--good)";
}
function accColor(pct){
  if(pct>=70) return "var(--good)";
  if(pct>=40) return "var(--mid)";
  return "var(--bad)";
}
