/* ---- MCQ: shuffled options, self-graded by clicking, no hinting ---- */
function shuffle(arr){
  const a = arr.slice();
  for(let i=a.length-1;i>0;i--){ const j=Math.floor(Math.random()*(i+1)); [a[i],a[j]]=[a[j],a[i]]; }
  return a;
}
function renderMCQ(){
  const body = document.getElementById("mcqBody");
  body.innerHTML = MCQ.map((m,i)=>{
    const opts = shuffle(m.options);
    return `<div class="quizcard" data-id="mcq-${i}" data-correct="${m.correct.replace(/"/g,'&quot;')}">
      <div class="q">${m.q}</div>
      <div class="mcq-opts">
        ${opts.map(o=>`<button class="mcq-opt" data-val="${o.replace(/"/g,'&quot;')}">${o}</button>`).join("")}
      </div>
      <div class="reveal mcq-why"><b style="color:var(--ink)">Γιατί:</b> ${m.why}</div>
    </div>`;
  }).join("");
  body.querySelectorAll(".quizcard").forEach(card=>{
    const id = card.dataset.id;
    const correct = card.dataset.correct;
    const why = card.querySelector(".mcq-why");
    card.querySelectorAll(".mcq-opt").forEach(btn=>{
      btn.onclick = ()=>{
        if(card.dataset.answered) return;
        card.dataset.answered = "1";
        const isCorrect = btn.dataset.val === correct;
        card.querySelectorAll(".mcq-opt").forEach(b2=>{
          b2.disabled = true;
          if(b2.dataset.val === correct) b2.classList.add("opt-correct");
          else if(b2===btn) b2.classList.add("opt-wrong");
        });
        why.classList.add("show");
        rate(id, isCorrect ? "got" : "miss");
      };
    });
  });
}

/* ---- MATCHING: tap an item in A, then its pair in B ---- */
let matchState = {setIdx:0, selectedA:null, solved:new Set()};
function renderMatchPicker(){
  const sel = document.getElementById("matchPicker");
  sel.innerHTML = MATCH.map((s,i)=>`<option value="${i}">${s.title}</option>`).join("");
  sel.value = matchState.setIdx;
  sel.onchange = ()=>{ matchState = {setIdx:+sel.value, selectedA:null, solved:new Set()}; renderMatch(); };
}
function renderMatch(){
  const set = MATCH[matchState.setIdx];
  const aList = set.pairs.map((p,i)=>({i,text:p[0]}));
  const bList = shuffle(set.pairs.map((p,i)=>({i,text:p[1]})));
  const wrap = document.getElementById("matchBody");
  wrap.innerHTML = `
    <div style="display:flex;gap:10px">
      <div style="flex:1" id="matchColA"></div>
      <div style="flex:1" id="matchColB"></div>
    </div>
    <div class="note" id="matchStatus" style="margin-top:14px"></div>`;
  const colA = document.getElementById("matchColA");
  const colB = document.getElementById("matchColB");
  function pillHtml(item, col){
    const solved = matchState.solved.has(item.i);
    const sel = matchState.selectedA===item.i && col==="a";
    return `<button data-i="${item.i}" data-col="${col}" class="match-pill ${solved?'solved':''} ${sel?'selected':''}" ${solved?'disabled':''}>${item.text}</button>`;
  }
  colA.innerHTML = aList.map(it=>pillHtml(it,"a")).join("");
  colB.innerHTML = bList.map(it=>pillHtml(it,"b")).join("");
  function attach(){
    wrap.querySelectorAll('.match-pill[data-col="a"]').forEach(btn=>{
      btn.onclick = ()=>{ matchState.selectedA = +btn.dataset.i; renderMatch(); };
    });
    wrap.querySelectorAll('.match-pill[data-col="b"]').forEach(btn=>{
      btn.onclick = ()=>{
        if(matchState.selectedA===null) return;
        const aIdx = matchState.selectedA, bIdx = +btn.dataset.i;
        const id = `match-${matchState.setIdx}-${aIdx}`;
        if(aIdx===bIdx){
          matchState.solved.add(aIdx);
          matchState.selectedA = null;
          rate(id, "got");
          renderMatch();
        }else{
          rate(id, "shaky");
          btn.classList.add("flash-wrong");
          setTimeout(()=>{ matchState.selectedA=null; renderMatch(); }, 550);
        }
      };
    });
  }
  attach();
  const status = document.getElementById("matchStatus");
  if(matchState.solved.size===set.pairs.length) status.textContent = "Όλα σωστά ✓ — άλλαξε σετ από το dropdown.";
}

