/* ============================ EXERCISE ENGINE (real data, rule-based) ============================ */
function shuffleArr(a){ a = a.slice(); for(let i=a.length-1;i>0;i--){ const j=Math.floor(Math.random()*(i+1)); [a[i],a[j]]=[a[j],a[i]]; } return a; }
function pick(arr){ return arr[Math.floor(Math.random()*arr.length)]; }

function shortenExpl(expl){
  if(!expl) return "";
  let t = expl.split(/\s+(στο|στη|στον|στην|στα|στις|στους)\s+/)[0];
  t = t.split(/\.\s/)[0];
  t = t.replace(/^\(/,"").trim();
  if(t.length > 90) t = t.slice(0,90).trim();
  return t;
}

// --- Recognition drill (word-level), sourced from WORD_TAGS (human-authored per-word morphology) ---
function genRecogQuestion(scope){
  const lecs = scope==="all" ? Object.keys(WORD_TAGS) : [scope.replace("E","")];
  const validLecs = lecs.filter(l=>WORD_TAGS[l] && WORD_TAGS[l].length>3);
  if(validLecs.length===0) return null;
  const lec = pick(validLecs);
  const pool = WORD_TAGS[lec];
  const idx = Math.floor(Math.random()*pool.length);
  const item = pool[idx];
  const distractPool = pool.filter((e,i)=>i!==idx).map(e=>e.t);
  const distract = shuffleArr([...new Set(distractPool)]).filter(t=>t!==item.t).slice(0,3);
  if(distract.length<3) return null;
  const options = shuffleArr([item.t, ...distract]);
  const lecObj = LECTIOS.find(l=>l.id===`E${lec}`);
  return {
    id: `recog-${lec}-${idx}`,
    kind: "recog",
    lectio: `E${lec}`,
    prompt: `Πώς αναγνωρίζεις τη λέξη «${item.f}»;`,
    sub: lecObj ? lecObj.roman : "",
    options, correct: item.t, meaning: item.m
  };
}

// --- Syntax-role drill, sourced directly from LECTIOS[].syntax (already real, per-lectio) ---
function genSyntaxRoleQuestion(scope){
  const lecs = scope==="all" ? LECTIOS : LECTIOS.filter(l=>l.id===scope);
  const valid = lecs.filter(l=>l.syntax && l.syntax.length>4);
  if(valid.length===0) return null;
  const lec = pick(valid);
  const idx = Math.floor(Math.random()*lec.syntax.length);
  const q = lec.syntax[idx];
  const tag = shortenExpl(q.expl);
  if(!tag || tag.length<5) return genSyntaxRoleQuestion(scope);
  const distractPool = lec.syntax.filter((x,i)=>i!==idx).map(x=>shortenExpl(x.expl)).filter(t=>t && t.length>4 && t!==tag);
  const distract = shuffleArr([...new Set(distractPool)]).slice(0,3);
  if(distract.length<3) return null;
  const options = shuffleArr([tag, ...distract]);
  return {
    id: `${lec.id}-q${idx}`,
    kind: "syntax",
    lectio: lec.id,
    prompt: `Τι ρόλο/λειτουργία έχει το «${q.lemma}» (${lec.roman});`,
    sub: lec.roman,
    options, correct: tag, meaning: q.expl
  };
}

// --- Principal-parts drill, sourced from VOCAB_DATA[].verbs (real principal parts) ---
function cleanPart(p){ return p.replace(/\s*\([^)]*\)\s*$/,"").trim(); }
function genVerbPartsQuestion(scope){
  const lecs = scope==="all" ? Object.keys(VOCAB_DATA) : [scope.replace("E","")];
  const allVerbsByPos = {0:[],1:[],2:[],3:[]};
  Object.keys(VOCAB_DATA).forEach(lec=>{
    (VOCAB_DATA[lec].verbs||[]).forEach(v=>{
      const parts = v.parts.split(",").map(cleanPart).filter(p=>p && p!=="-" && p!=="―");
      if(parts.length>=3) parts.forEach((p,i)=>{ if(i<4) allVerbsByPos[i].push(p); });
    });
  });
  const validLecs = lecs.filter(l=>VOCAB_DATA[l] && (VOCAB_DATA[l].verbs||[]).some(v=>v.parts.split(",").length>=3));
  if(validLecs.length===0) return null;
  const lec = pick(validLecs);
  const candidates = (VOCAB_DATA[lec].verbs||[]).filter(v=>{
    const parts = v.parts.split(",").map(cleanPart).filter(p=>p && p!=="-" && p!=="―");
    return parts.length>=3;
  });
  if(candidates.length===0) return null;
  const vIdx = Math.floor(Math.random()*candidates.length);
  const v = candidates[vIdx];
  const parts = v.parts.split(",").map(cleanPart).filter(p=>p && p!=="-" && p!=="―");
  const hideIdx = 1 + Math.floor(Math.random()*(parts.length-1)); // never hide the lemma (index 0)
  const correct = parts[hideIdx];
  const shown = parts.map((p,i)=> i===hideIdx ? "____" : p).join(", ");
  const distractPool = (allVerbsByPos[hideIdx]||[]).filter(p=>p!==correct);
  const distract = shuffleArr([...new Set(distractPool)]).slice(0,3);
  if(distract.length<3) return null;
  const options = shuffleArr([correct, ...distract]);
  const realIdx = VOCAB_DATA[lec].verbs.indexOf(v);
  const posLabel = ["", "παρακείμενος", "σουπίνο", "απαρέμφατο"][hideIdx] || "αρχικός τύπος";
  return {
    id: `vparts-${lec}-${realIdx}`,
    kind: "vparts",
    lectio: `E${lec}`,
    prompt: `Συμπλήρωσε τον ${posLabel} του ρήματος: ${shown}`,
    sub: `Lectio ${lec}`,
    options, correct, meaning: v.parts
  };
}

// --- Number transform (Α'/Β' declension only — rule-based, regular paradigms) ---
function declensionParadigm(noun){
  const lemma = noun.lemma;
  const g = noun.gender || "";
  if(g.includes("δεν")) return null;
  if(noun.decl==="Α" && lemma.endsWith("a")){
    const s = lemma.slice(0,-1);
    return {singular:{ονομαστική:s+"a",γενική:s+"ae",δοτική:s+"ae",αιτιατική:s+"am",αφαιρετική:s+"a"},
            plural:{ονομαστική:s+"ae",γενική:s+"arum",δοτική:s+"is",αιτιατική:s+"as",αφαιρετική:s+"is"}};
  }
  if(noun.decl==="Β" && lemma.endsWith("us") && g.startsWith("αρσ")){
    const s = lemma.slice(0,-2);
    return {singular:{ονομαστική:s+"us",γενική:s+"i",δοτική:s+"o",αιτιατική:s+"um",αφαιρετική:s+"o"},
            plural:{ονομαστική:s+"i",γενική:s+"orum",δοτική:s+"is",αιτιατική:s+"os",αφαιρετική:s+"is"}};
  }
  if(noun.decl==="Β" && lemma.endsWith("um") && g.startsWith("ουδ")){
    const s = lemma.slice(0,-2);
    return {singular:{ονομαστική:s+"um",γενική:s+"i",δοτική:s+"o",αιτιατική:s+"um",αφαιρετική:s+"o"},
            plural:{ονομαστική:s+"a",γενική:s+"orum",δοτική:s+"is",αιτιατική:s+"a",αφαιρετική:s+"is"}};
  }
  return null;
}
function genNumberTransformQuestion(scope){
  const lecs = scope==="all" ? Object.keys(VOCAB_DATA) : [scope.replace("E","")];
  let pool = [];
  lecs.forEach(lec=>{
    (VOCAB_DATA[lec] && VOCAB_DATA[lec].nouns || []).forEach(n=>{
      const p = declensionParadigm(n);
      if(p) pool.push({lec, noun:n, paradigm:p});
    });
  });
  if(pool.length===0) return null;
  const item = pick(pool);
  const cases = ["ονομαστική","γενική","δοτική","αιτιατική","αφαιρετική"];
  const cs = pick(cases);
  const fromNum = pick(["singular","plural"]);
  const toNum = fromNum==="singular" ? "plural" : "singular";
  const given = item.paradigm[fromNum][cs];
  const correct = item.paradigm[toNum][cs];
  let distractPool = [...new Set(Object.values(item.paradigm[toNum]))].filter(v=>v!==correct);
  if(distractPool.length<3){
    const extra = [...new Set(Object.values(item.paradigm[fromNum]))].filter(v=>v!==given && v!==correct && !distractPool.includes(v));
    distractPool = distractPool.concat(extra);
  }
  const options = shuffleArr([correct, ...shuffleArr(distractPool).slice(0,3)]);
  if(options.length<2) return null;
  const numLabel = {singular:"ενικός", plural:"πληθυντικός"};
  return {
    id: `numtr-${item.lec}-${item.noun.lemma}-${cs}-${fromNum}`,
    kind: "numtr",
    lectio: `E${item.lec}`,
    prompt: `Δώσε το «${given}» (${cs}, ${numLabel[fromNum]}) στον αντίθετο αριθμό:`,
    sub: `${item.noun.lemma} — Lectio ${item.lec}`,
    options, correct, meaning: `${item.noun.lemma}, ${item.noun.gender}, ${item.noun.decl}΄ κλίση`
  };
}

const EXERCISE_GENERATORS = [genRecogQuestion, genSyntaxRoleQuestion, genVerbPartsQuestion, genNumberTransformQuestion];

/* ============================ ACCURACY TRACKER (per drill kind, persisted) ============================ */
function getKindStat(kind){
  try{
    const raw = localStorage.getItem("stat:"+kind);
    return raw ? JSON.parse(raw) : {correct:0, total:0};
  }catch(e){ return {correct:0, total:0}; }
}
function trackAnswer(kind, isCorrect){
  const s = getKindStat(kind);
  s.total++;
  if(isCorrect) s.correct++;
  try{ localStorage.setItem("stat:"+kind, JSON.stringify(s)); }catch(e){}
}

/* ============================ NEW GENERATORS: real-data sourced ============================ */

// Φαινόμενο από πραγματικό παράδειγμα (καλύπτει σκοπό, δευτερεύουσες, ACI, ablativus absolutus, κ.λπ.)
function genPhenomenonQuestion(scope){
  let pool = PHENOMENA;
  if(scope!=="all"){
    const num = scope.replace("E","");
    pool = PHENOMENA.filter(p=>p.src && p.src.includes(num));
    if(pool.length===0) pool = PHENOMENA;
  }
  const item = pick(pool);
  const distractTitles = shuffleArr(PHENOMENA.filter(p=>p.title!==item.title).map(p=>p.title)).slice(0,3);
  if(distractTitles.length<3) return null;
  const options = shuffleArr([item.title, ...distractTitles]);
  return {
    id: `phenom-${item.title}`,
    kind: "phenom",
    lectio: scope,
    prompt: `Ποιο φαινόμενο αναγνωρίζεις σε αυτό το παράδειγμα; «${item.ex}»`,
    sub: "Φαινόμενα",
    options, correct: item.title, meaning: item.tip
  };
}

// Λεξιλογικές / ετυμολογικές — σημασία λέξης (από τη γραμματική ανάλυση κάθε lectio)
function genVocabMeaningQuestion(scope){
  const lecs = scope==="all" ? Object.keys(WORD_TAGS) : [scope.replace("E","")];
  const validLecs = lecs.filter(l=>WORD_TAGS[l] && WORD_TAGS[l].length>4);
  if(validLecs.length===0) return null;
  const lec = pick(validLecs);
  const pool = WORD_TAGS[lec].filter(e=>e.m && e.m.length>1 && e.m.length<40);
  if(pool.length<4) return null;
  const idx = Math.floor(Math.random()*pool.length);
  const item = pool[idx];
  const distract = shuffleArr(pool.filter((e,i)=>i!==idx).map(e=>e.m)).filter(m=>m!==item.m).slice(0,3);
  if(distract.length<3) return null;
  const options = shuffleArr([item.m, ...distract]);
  const lecObj = LECTIOS.find(l=>l.id===`E${lec}`);
  return {
    id: `vocab-${lec}-${idx}`,
    kind: "vocab",
    lectio: `E${lec}`,
    prompt: `Τι σημαίνει το «${item.f}»;`,
    sub: lecObj ? lecObj.roman : "",
    options, correct: item.m, meaning: item.t
  };
}

// Παραθετικά — από πραγματικά καταγεγραμμένα παραθετικά (ή "δεν σχηματίζει")
function genParathetikaQuestion(scope){
  const lecs = scope==="all" ? Object.keys(PARATHETIKA_DATA) : [scope.replace("E","")];
  let withDegrees = [], noDegree = [];
  lecs.forEach(lec=>{
    (PARATHETIKA_DATA[lec]||[]).forEach(a=>{
      if(a.comp) withDegrees.push({...a, lec});
      else if(a.no_degree) noDegree.push({...a, lec});
    });
  });
  // also fold in the 5 classic irregulars from MORPH for variety
  const irregular = [
    {lemma:"bonus", comp:"melior", sup:"optimus", lec:"-"},
    {lemma:"malus", comp:"peior", sup:"pessimus", lec:"-"},
    {lemma:"magnus", comp:"maior", sup:"maximus", lec:"-"},
    {lemma:"parvus", comp:"minor", sup:"minimus", lec:"-"},
  ];
  withDegrees = withDegrees.concat(irregular);
  if(Math.random()<0.3 && noDegree.length>3){
    // "which one does NOT form degrees" type question
    const correct = pick(noDegree);
    const distract = shuffleArr(withDegrees.filter(d=>d.lemma!==correct.lemma)).slice(0,3).map(d=>d.lemma);
    if(distract.length<3) return null;
    const options = shuffleArr([correct.lemma, ...distract]);
    return {
      id: `parath-nodeg-${correct.lemma}`,
      kind: "parathetika",
      lectio: correct.lec!=="-" ? `E${correct.lec}` : "all",
      prompt: `Ποιο από αυτά τα επίθετα ΔΕΝ σχηματίζει παραθετικά;`,
      sub: "Παραθετικά",
      options, correct: correct.lemma, meaning: `${correct.lemma} δεν σχηματίζει παραθετικά (περιφραστικά αν χρειαστεί: magis/maxime + επίθετο).`
    };
  }
  if(withDegrees.length<4) return null;
  const item = pick(withDegrees);
  const askSup = Math.random()<0.5;
  const correct = askSup ? item.sup : item.comp;
  const distractPool = withDegrees.filter(d=>d.lemma!==item.lemma).map(d=>askSup?d.sup:d.comp);
  const distract = shuffleArr([...new Set(distractPool)]).slice(0,3);
  if(distract.length<3) return null;
  const options = shuffleArr([correct, ...distract]);
  return {
    id: `parath-${item.lemma}-${askSup?"sup":"comp"}`,
    kind: "parathetika",
    lectio: item.lec!=="-" ? `E${item.lec}` : "all",
    prompt: `Ποιος είναι ο ${askSup?"υπερθετικός":"συγκριτικός"} βαθμός του «${item.lemma}»;`,
    sub: "Παραθετικά",
    options, correct, meaning: `${item.lemma} → συγκρ.: ${item.comp}, υπερθ.: ${item.sup}`
  };
}

// Τονισμός — βασισμένο στη συζυγία (κανόνας 100% αξιόπιστος, όχι μαντεψιά)
function syllablesOf(word){
  return (word.match(/[aeiouyāēīōūăĕĭŏŭ]+/gi) || []).length;
}
function genTonismosQuestion(scope){
  const lecs = scope==="all" ? Object.keys(VOCAB_DATA) : [scope.replace("E","")];
  let pool = [];
  lecs.forEach(lec=>{
    (VOCAB_DATA[lec] && VOCAB_DATA[lec].verbs || []).forEach(v=>{
      const conj = v.conj;
      if(["1","2","3","4"].includes(conj)){
        const parts = v.parts.split(",").map(cleanPart);
        const inf = parts[parts.length-1];
        if(inf && inf.length>2) pool.push({inf, conj, lec});
      }
    });
  });
  if(pool.length===0) return null;
  const item = pick(pool);
  const plain = item.inf.normalize("NFD").replace(/[\u0300-\u036f]/g,"");
  const nsyl = syllablesOf(plain);
  const stressOnPenult = ["1","2","4"].includes(item.conj) || nsyl<=2;
  const correct = stressOnPenult ? "παραλήγουσα" : "προπαραλήγουσα";
  const wrong = stressOnPenult ? "προπαραλήγουσα" : "παραλήγουσα";
  const options = shuffleArr([correct, wrong, "λήγουσα"]);
  return {
    id: `tonismos-${item.inf}`,
    kind: "tonismos",
    lectio: `E${item.lec}`,
    prompt: `Σε ποια συλλαβή τονίζεται το απαρέμφατο «${item.inf}»;`,
    sub: `${item.conj}η συζυγία`,
    options, correct,
    meaning: `${["","Α'","Β'","Γ'","Δ'"][item.conj]} συζυγία: ${["","το -āre/-ēre/-īre είναι μακρό → παραλήγουσα","","το -ĕre είναι βραχύ → προπαραλήγουσα",""][item.conj] || (stressOnPenult?"μακρό φωνήεν στην παραλήγουσα":"βραχύ φωνήεν, τονίζεται η προπαραλήγουσα")}`
  };
}

EXERCISE_GENERATORS.push(genPhenomenonQuestion, genVocabMeaningQuestion, genParathetikaQuestion, genTonismosQuestion);

