const KIND_GENERATOR_MAP = {recog:genRecogQuestion, syntax:genSyntaxRoleQuestion, vparts:genVerbPartsQuestion, numtr:genNumberTransformQuestion};
function genMixedQuestion(scope){
  if(homePreferredKind){
    const gen = KIND_GENERATOR_MAP[homePreferredKind] || (homePreferredKind==="phenom"?genPhenomenonQuestion:homePreferredKind==="vocab"?genVocabMeaningQuestion:homePreferredKind==="parathetika"?genParathetikaQuestion:homePreferredKind==="tonismos"?genTonismosQuestion:null);
    if(gen){
      for(let tries=0; tries<6; tries++){
        const q = gen(scope);
        if(q){ homePreferredKind = null; return q; }
      }
    }
    homePreferredKind = null;
  }
  for(let tries=0; tries<8; tries++){
    const gen = pick(EXERCISE_GENERATORS);
    const q = gen(scope);
    if(q) return q;
  }
  return null;
}

let exerciseScope = "all";
let currentQuestion = null;
let exerciseStats = {correct:0, total:0};

function renderExercisePicker(){
  const sel = document.getElementById("exerciseScope");
  if(!sel) return;
  sel.innerHTML = `<option value="all">Όλα τα Lectio</option>` +
    LECTIOS.map(l=>`<option value="${l.id}">${l.roman}</option>`).join("");
  sel.value = exerciseScope;
}

function renderExerciseQuestion(){
  const body = document.getElementById("exerciseBody");
  if(!body) return;
  currentQuestion = genMixedQuestion(exerciseScope);
  if(!currentQuestion){
    body.innerHTML = `<div class="empty">Δεν βρέθηκαν αρκετά δεδομένα για αυτό το lectio. Δοκίμασε "Όλα τα Lectio".</div>`;
    return;
  }
  const q = currentQuestion;
  const kindBadge = {recog:"Αναγνώριση", syntax:"Συντακτικό", vparts:"Αρχικοί χρόνοι", numtr:"Αριθμός", phenom:"Φαινόμενο/Πρόταση", vocab:"Λεξιλόγιο", parathetika:"Παραθετικά", tonismos:"Τονισμός"}[q.kind] || q.kind;
  body.innerHTML = `
    <div class="quizcard">
      <div class="badge b-neutral">${kindBadge} · ${q.sub}</div>
      <div class="q">${q.prompt}</div>
      <div class="mcq-opts" id="exOpts">
        ${q.options.map((o,i)=>`<button class="mcq-opt" data-i="${i}">${o}</button>`).join("")}
      </div>
      <div class="mcq-why" id="exWhy">
        <div class="tip">${q.meaning || ""}</div>
        <div class="actions">
          <button class="btn miss" data-r="miss">Το έχασα</button>
          <button class="btn shaky" data-r="shaky">Λίγη σιγουριά</button>
          <button class="btn got" data-r="got">Το ήξερα</button>
        </div>
      </div>
    </div>
    <div class="note">Σκορ αυτής της συνεδρίας: ${exerciseStats.correct} / ${exerciseStats.total}</div>
  `;
  document.querySelectorAll("#exOpts .mcq-opt").forEach(btn=>{
    btn.onclick = ()=>{
      const i = +btn.dataset.i;
      const isCorrect = q.options[i] === q.correct;
      document.querySelectorAll("#exOpts .mcq-opt").forEach((b2,i2)=>{
        b2.onclick = null;
        if(q.options[i2]===q.correct) b2.classList.add("opt-correct");
        else if(i2===i) b2.classList.add("opt-wrong");
      });
      document.getElementById("exWhy").classList.add("show");
      exerciseStats.total++;
      if(isCorrect) exerciseStats.correct++;
      trackAnswer(q.kind, isCorrect);
      rate(q.id, isCorrect ? "got" : "miss");
    };
  });
  document.querySelectorAll("#exWhy .actions .btn").forEach(btn=>{
    btn.onclick = ()=>{
      rate(q.id, btn.dataset.r);
      renderExerciseQuestion();
    };
  });
}

