/* ============================ MOCK EXAM ============================ */
const MOCK_LEN = 12;
let mockState = null; // {questions:[], idx:0, answers:[], started, finished}

function buildMockExam(){
  const qs = [];
  // 2 real translation prompts
  const lecPool = shuffleArr(LECTIOS);
  for(let i=0;i<2 && i<lecPool.length;i++){
    const lec = lecPool[i];
    const s = pick(lec.sentences);
    qs.push({type:"translate", lectio:lec.roman, lat:s.lat, gr:s.gr});
  }
  let tries = 0;
  while(qs.length < MOCK_LEN && tries < 60){
    tries++;
    const q = genMixedQuestion("all");
    if(q) qs.push({type:"mcq", data:q});
  }
  return qs;
}

